<template>
    <div>
        <echart-Component    
            :options="options"
            id="customer_pie_chart"
            height="260px"
            width="100%" 
        />
    </div>
</template>

<script>
export default{
    data() {
        return {
            options:{
                grid: {
                    show: true,                                 //是否显示图表背景网格    
                    left: '30',                                    //图表距离容器左侧多少距离
                    right: '30',                                //图表距离容器右侧侧多少距离
                    bottom: '50',                              //图表距离容器上面多少距离
                    top: 10,                                       //图表距离容器下面多少距离
                    containLabel: true,                     //防止标签溢出  
                    // backgroundColor:'#555555',     //网格背景色，默认透明
                },
                dataset: {
                    dimensions:['dept','age'],//设置x轴和y轴的数据
                    source:[
                    {dept:'5',age:'北京',num:'10'},
                    {dept:'10',age:'天津',num:'30'},
                    {dept:'15',age:'重庆',num:'10'},
                    {dept:'20',age:'河南',num:'10'},
                    {dept:'10',age:'湖南',num:'10'},
                    {dept:'15',age:'山东',num:'10'},
                    {dept:'10',age:'广东',num:'10'},
                    {dept:'10',age:'江苏',num:'10'},
                    {dept:'25',age:'福建',num:'10'},
                    {dept:'xx',age:'浙江',num:'10'},
                    {dept:'15',age:'四川',num:'10'},
                    {dept:'xx',age:'上海',num:'8'},
                    {dept:'xx',age:'黑龙江',num:'10'},
                    ],
                },
                xAxis: {
                    type:'category',
                    axisTick:{
                    show:false
                    },
                    axisLine:{
                    show:true,
                    lineStyle:{
                        color:'#000',
                        width:1,
                        type:'solid',
                    }
                    },
                    splitLine:{
                    show:true,
                    lineStyle:{
                        color:'#ccc',
                        type: [20, 5],//20为虚线长度，5为间距
                        dashOffset: 0//距离x轴的距离
                    }
                    }
                },
                yAxis: {
                    type:'category',
                    axisTick:{
                    show:false
                    },
                    axisLine:{
                    show:true,
                    lineStyle:{
                        color:'#000',
                        width:1,
                        type:'solid',
                    }
                    },
                    splitLine:{
                    show:true,
                    lineStyle:{
                        color:'#ccc',
                        width:1,
                    type: [20, 5],//20为虚线长度，5为间距
                    dashOffset: 0//距离y轴的距离
                    }
                    
                    }
                },
                series: [
                    {
                    type: 'scatter',
                    symbolSize(data){
                        //根据数据大小来动态设置散点的大小（但是不能超出方框外面）
                        let result = parseInt(data.num)*5;
                        if (result>0 && result < 25) {
                        result = 25;
                        }else if(result>100){
                        result = 100;
                        }
                        return result;
                    },
                    //显示中心的文字
                    label:{
                        show:true,
                        fontSize:16,
                        position:'inside',
                        color:'#fff',
                        formatter(params){
                            console.log(params)
                        return params.value.num+ params.value.age
                        }
                    },
                    itemStyle:{
                        color(params){
                        let color = '';
                        let num = parseFloat(params.value.num);
                        if(num<=10){
                            color = '#5B8FF9';
                        }else if(num>10 && num<=20){
                            color = '#5AD8A6';
                        }else{
                            color = '#5D7092';
                        }
                        return color;
                        }
                    }
                    }
                ]
            }
        }
    },
}
</script>

