    consumable_chart,
    state_chart,
    sales_statistics,
    regional_scatter_map
  },
  async created(){

  },
  mounted() {
    this.timeFn()
    this.cancelLoading()
    this.index++
  },
  beforeDestroy () {
    clearInterval(this.timing)
  },
  methods: {
    timeFn() {
      this.timing = setInterval(() => {
        this.dateDay = formatTime(new Date(), 'HH: mm: ss')
        this.dateYear = formatTime(new Date(), 'yyyy-MM-dd')
        this.dateWeek = this.weekday[new Date().getDay()]
      }, 1000)
    },
    cancelLoading() {
      setTimeout(() => {
        this.loading = false
      }, 1000)
    }
  }
